#include <stdio.h>
#include <time.h>
#include <string.h> // Required for strftime

// Define the name of the log file
#define LOG_FILE_NAME "application_errors.log"

/**
 * @brief Internal function to write an error message to a log file with detailed information.
 *
 * This function opens the predefined log file in append mode, retrieves the current timestamp,
 * and formats a detailed error message including the timestamp, the file and line number
 * where the error occurred, and the actual error message provided by the caller.
 *
 * If the log file cannot be opened, an error message is printed to stderr as a fallback.
 *
 * @param message The error message string to be logged. This string will be treated as plain text.
 * @param file The name of the source file where the error occurred (typically __FILE__).
 * @param line The line number in the source file where the error occurred (typically __LINE__).
 */
void log_error_internal(const char *message, const char *file, int line) {
    FILE *logfile = NULL;
    time_t current_time;
    char time_str[64]; // Buffer to store the formatted timestamp

    // Open the log file in append mode ("a"). If the file doesn't exist, it will be created.
    logfile = fopen(LOG_FILE_NAME, "a");
    if (logfile == NULL) {
        // Fallback: If the log file cannot be opened, print the error to stderr.
        fprintf(stderr, "ERROR: Could not open log file '%s' for writing. Message: %s at %s:%d\n",
                LOG_FILE_NAME, message, file, line);
        return; // Exit the function as logging to file failed
    }

    // Get the current time
    time(&current_time);

    // Format the current time into a human-readable string.
    // strftime provides more control over the format than ctime.
    strftime(time_str, sizeof(time_str), "%Y-%m-%d %H:%M:%S", localtime(&current_time));

    // Write the detailed error message to the log file.
    // The message parameter is treated as a string (%s) to prevent format string vulnerabilities.
    fprintf(logfile, "[%s] [%s:%d] ERROR: %s\n", time_str, file, line, message);

    // Close the log file. It's important to close the file after writing.
    fclose(logfile);
}

/**
 * @brief Macro for convenient error logging.
 *
 * This macro automatically passes the current source file name (__FILE__) and
 * line number (__LINE__) to the log_error_internal function, making it easier
 * to log errors with detailed context.
 *
 * Usage: LOG_ERROR("An unexpected error occurred.");
 *
 * @param message The error message string to be logged.
 */
#define LOG_ERROR(message) log_error_internal(message, __FILE__, __LINE__)

